import{_ as i,o as a,c as t,a4 as r}from"./chunks/framework.BY9PERBP.js";const b=JSON.parse('{"title":"Interface: SplitViewOptions · ui","description":"","frontmatter":{"title":"Interface: SplitViewOptions · ui"},"headers":[],"relativePath":"api/ui/interfaces/SplitViewOptions.md","filePath":"api/ui/interfaces/SplitViewOptions.md"}'),s={name:"api/ui/interfaces/SplitViewOptions.md"};function o(n,e,c,l,d,p){return a(),t("div",null,[...e[0]||(e[0]=[r('<p><a href="./../">@jsvision/ui</a> / SplitViewOptions</p><h1 id="interface-splitviewoptions" tabindex="-1">Interface: SplitViewOptions <a class="header-anchor" href="#interface-splitviewoptions" aria-label="Permalink to &quot;Interface: SplitViewOptions&quot;">​</a></h1><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/ui/src/split/split-view.ts#L53" target="_blank" rel="noreferrer">ui/src/split/split-view.ts:53</a></p><p>Construction options for <a href="./../classes/SplitView.html">SplitView</a>.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="children" tabindex="-1">children <a class="header-anchor" href="#children" aria-label="Permalink to &quot;children&quot;">​</a></h3><blockquote><p><strong>children</strong>: <a href="./../classes/View.html"><code>View</code></a>[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/ui/src/split/split-view.ts#L57" target="_blank" rel="noreferrer">ui/src/split/split-view.ts:57</a></p><p>The pane views, in order. N children produce N−1 splitters.</p><hr><h3 id="direction" tabindex="-1">direction <a class="header-anchor" href="#direction" aria-label="Permalink to &quot;direction&quot;">​</a></h3><blockquote><p><strong>direction</strong>: <a href="./../type-aliases/Direction.html"><code>Direction</code></a></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/ui/src/split/split-view.ts#L55" target="_blank" rel="noreferrer">ui/src/split/split-view.ts:55</a></p><p>Split axis: <code>&#39;row&#39;</code> = side-by-side panes, <code>&#39;col&#39;</code> = stacked panes.</p><hr><h3 id="grabmark" tabindex="-1">grabMark? <a class="header-anchor" href="#grabmark" aria-label="Permalink to &quot;grabMark?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>grabMark?</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/ui/src/split/split-view.ts#L71" target="_blank" rel="noreferrer">ui/src/split/split-view.ts:71</a></p><p>Whether each splitter draws the <code>▓</code> grab mark at its midpoint. Defaults to <code>true</code>. This is only the initial value — the live state lives in the public <a href="./../classes/SplitView.html#grabmark">SplitView.grabMark</a> signal, so you can flip it at runtime.</p><hr><h3 id="minsize" tabindex="-1">minSize? <a class="header-anchor" href="#minsize" aria-label="Permalink to &quot;minSize?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>minSize?</strong>: <code>number</code> | <code>number</code>[]</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/ui/src/split/split-view.ts#L65" target="_blank" rel="noreferrer">ui/src/split/split-view.ts:65</a></p><p>Minimum pane size in cells — a scalar applies to every pane, an array is per-pane.</p><hr><h3 id="onresize" tabindex="-1">onResize? <a class="header-anchor" href="#onresize" aria-label="Permalink to &quot;onResize?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onResize?</strong>: (<code>sizes</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/ui/src/split/split-view.ts#L77" target="_blank" rel="noreferrer">ui/src/split/split-view.ts:77</a></p><p>Fired on every <strong>live</strong> change: each drag move that actually changes the sizes, and each keyboard step. Never fires when the sizes are unchanged — a drag held against a minimum is a silent no-op. Use this to mirror the layout live; use <a href="#onresizeend">SplitViewOptions.onResizeEnd</a> to persist it.</p><h4 id="parameters" tabindex="-1">Parameters <a class="header-anchor" href="#parameters" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="sizes" tabindex="-1">sizes <a class="header-anchor" href="#sizes" aria-label="Permalink to &quot;sizes&quot;">​</a></h5><p><code>number</code>[]</p><h4 id="returns" tabindex="-1">Returns <a class="header-anchor" href="#returns" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="onresizeend" tabindex="-1">onResizeEnd? <a class="header-anchor" href="#onresizeend" aria-label="Permalink to &quot;onResizeEnd?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>onResizeEnd?</strong>: (<code>sizes</code>) =&gt; <code>void</code></p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/ui/src/split/split-view.ts#L83" target="_blank" rel="noreferrer">ui/src/split/split-view.ts:83</a></p><p>Fired once per <strong>commit</strong>: the pointer-up that ends a drag, and each discrete keyboard step. One drag gesture fires this exactly once however far the pointer travelled — so this, not <a href="#onresize">SplitViewOptions.onResize</a>, is the hook to persist a layout from.</p><h4 id="parameters-1" tabindex="-1">Parameters <a class="header-anchor" href="#parameters-1" aria-label="Permalink to &quot;Parameters&quot;">​</a></h4><h5 id="sizes-1" tabindex="-1">sizes <a class="header-anchor" href="#sizes-1" aria-label="Permalink to &quot;sizes&quot;">​</a></h5><p><code>number</code>[]</p><h4 id="returns-1" tabindex="-1">Returns <a class="header-anchor" href="#returns-1" aria-label="Permalink to &quot;Returns&quot;">​</a></h4><p><code>void</code></p><hr><h3 id="sizes-2" tabindex="-1">sizes <a class="header-anchor" href="#sizes-2" aria-label="Permalink to &quot;sizes&quot;">​</a></h3><blockquote><p><strong>sizes</strong>: <a href="./Signal.html"><code>Signal</code></a>&lt;<code>number</code>[]&gt;</p></blockquote><p>Defined in: <a href="https://github.com/blendsdk/jsvision/blob/6920f1fe8de8c6c41b5094fc97c3533ec5cadb39/packages/ui/src/split/split-view.ts#L63" target="_blank" rel="noreferrer">ui/src/split/split-view.ts:63</a></p><p>Two-way pane sizing as <code>fr</code> weights. Seed it with ratios (<code>signal([1, 1])</code> = equal, <code>[2, 1]</code> = 2:1); a drag rewrites it with the resolved cell counts. Restoring saved weights into a differently-sized container rescales them proportionally.</p>',49)])])}const u=i(s,[["render",o]]);export{b as __pageData,u as default};
